export type AIFactoryConfig = {
  /**
  Unique identifier for the configuration (e.g., "quick_turn_taking").
  This can be used to reference the configuration.

  Example: `"group_chat"`
  */
  id: string;

  /**
  How many instances of this configuration are required.
  This should match the number of humans + bots, but it's validated separately.

  Example: `3`
  */
  n_instances: number;

  /**
  Configuration for the system message each AI receives.
  */
  system_message: SystemMessageConfig;

  /**
  Optional list of LLMs to use for the AI instances.
  If not provided, the default model from the client will be used.
  */
  llms?: VLLM[];

  /**
  Whether this configuration allows human participants.
  If specified as `true`, at least one human must be present in the instances.

  Example: `true`
  */
  allow_humans?: boolean;

  /**
  Optional configuration for persistence settings for this AI factory.
  */
  persistence?: PersistenceConfig;

  /**
  Optional list of tools (functions) that the AI can call.
  */
  tools?: CallableFunction[];

  /**
  Optional list of attachments (files, images, etc.) to include with AI responses.
  */
  attachments?: Attachment[];

  /**
  Optional metadata for the AI factory configuration.
  */
  metadata?: any;
};

export const DEFAULT_SYSTEM_MESSAGE = "You are a helpful AI assistant.";

/**
Generates VLLM objects for AI participants in a group conversation.
Uses either specified models or rotates through the available models.
Reserves slots for human(s) if requested.
Validates that the total participants (AI + human) matches the expected number.
*/
export function createAIFactory(config: AIFactoryConfig): VLLM[] {
  const {
    id,
    n_instances,
    system_message,
    llms,
    allow_humans = false,
    persistence,
    tools,
    attachments,
    metadata,
  } = config;

  // Use provided LLMs or fallback to default model rotation
  const availableModels = llms?.length 
    ? llms 
    : [GROK, GPT4O_MINI, CLAUDE_3_5_HAIKU, GEMINI_1_5_FLASH, LLAMA_3_1];

  // Determine how many AI instances to create
  let n_ai_instances = n_instances;
  if (allow_humans) {
    // If humans are allowed, we need at least 1 human slot
    n_ai_instances = n_instances - 1;
    if (n_ai_instances < 0) {
      throw new Error(`Configuration "${id}" requires at least 1 human when allow_humans is true, but n_instances is ${n_instances}`);
    }
  }

  // Create AI instances
  const ai_instances: VLLM[] = [];
  for (let i = 0; i < n_ai_instances; i++) {
    const model_idx = i % availableModels.length;
    const baseModel = availableModels[model_idx];

    const ai_instance: VLLM = {
      ...baseModel,
      model: baseModel.model,
      system_message: system_message.system_message,
      name: system_message.name || `AI-${i}`,
      persistence: persistence ? {
        ...persistence,
        optional_fields: ['attachments', ...(persistence.optional_fields || [])]
      } : undefined,
      tools,
      attachments,
      metadata: {
        ...metadata,
        ai_factory_config_id: id,
        ai_instance_index: i,
      },
    };
    ai_instances.push(ai_instance);
  }

  return ai_instances;
}
